namespace CursorConfig {
    constexpr float BLINK_PERIOD_MS = 1000.0f;    // Full blink cycle
    constexpr float FADE_MS = 150.0f;             // Fade in/out duration
    constexpr float MOVE_MS = 40.0f;              // Cursor position animation
    constexpr float PAUSE_MS = 500.0f;            // Pause before blink resumes
    constexpr uint32_t CURSOR_COLOR = 0xFFE0E0E0; // Light gray cursor
    constexpr float CURSOR_WIDTH = 2.0f;          // Cursor line width
}

// ============================================================================
// ContentWidget Construction/Destruction
// ============================================================================

// Helper to check if the editor (parent) has focus
static bool editor_has_focus(Widget* parent) {
    return parent && (parent->flags & WidgetFlags::Focused);
}

ContentWidget::ContentWidget() : Widget() {
    debug_name = "CodeEditor::ContentWidget";
    // Note: NOT focusable - parent CodeEditorWidget owns focus
    // Use editor_has_focus(parent) to check focus state for cursor rendering
    line_index_.set_line_height(ContentConfig::LINE_HEIGHT);

    // Heap-allocate line slots (128 slots × ~8KB each = ~1MB - too large for arena's 64KB blocks)
    line_slots_ = new (std::nothrow) LineSlot[ContentConfig::MAX_LINE_SLOTS];
    if (!line_slots_) return;  // Allocation failed

    // Initialize all slots as unbound
    for (size_t i = 0; i < ContentConfig::MAX_LINE_SLOTS; i++) {
        line_slots_[i].line_number = 0;
        line_slots_[i].layout = nullptr;
        line_slots_[i].text[0] = L'\0';
        line_slots_[i].cache_valid = false;
    }
}

ContentWidget::~ContentWidget() {
    unbind_all_lines();
    delete[] line_slots_;
    line_slots_ = nullptr;
    delete[] line_lexer_states_;
    line_lexer_states_ = nullptr;
    line_lexer_states_capacity_ = 0;
    line_lexer_states_count_ = 0;
}

// ============================================================================
// Document Management
// ============================================================================

void ContentWidget::set_document(TextDocument* doc) {
    if (document_ == doc) return;

    // Unbind all current lines
    unbind_all_lines();

    document_ = doc;
    scroll_y_ = 0.0f;
    scroll_x_ = 0.0f;
    max_content_width_ = 0.0f;

    // Free old state array
    delete[] line_lexer_states_;
    line_lexer_states_ = nullptr;
    line_lexer_states_capacity_ = 0;
    line_lexer_states_count_ = 0;

    if (document_) {
        // Build line index
        line_index_.build(document_->content());

        // Allocate and compute line states for O(1) block comment lookup
        size_t line_count = line_index_.line_count();
        if (line_count > 0) {
            line_lexer_states_ = new (std::nothrow) bool[line_count];
            if (line_lexer_states_) {
                line_lexer_states_capacity_ = line_count;
                compute_line_lexer_states();
            }
        }
    } else {
        line_index_.clear();
    }

    set_dirty();
}

// ============================================================================
// Scroll Control
// ============================================================================

void ContentWidget::set_scroll_y(float y) {
    float max_y = max_scroll_y();
    if (y < 0.0f) y = 0.0f;
    if (y > max_y) y = max_y;

    if (scroll_y_ != y) {
        scroll_y_ = y;
        update_visible_lines();
        set_dirty();
    }
}

void ContentWidget::set_scroll_x(float x) {
    float max_x = max_scroll_x();
    if (x < 0.0f) x = 0.0f;
    if (x > max_x) x = max_x;

    if (scroll_x_ != x) {
        scroll_x_ = x;
        set_dirty();
    }
}

float ContentWidget::max_scroll_y() const {
    float content_h = content_height();
    float viewport_h = rect.height;
    if (content_h <= viewport_h) return 0.0f;
    return content_h - viewport_h;
}

float ContentWidget::max_scroll_x() const {
    float viewport_w = rect.width - ContentConfig::PADDING_LEFT - ContentConfig::PADDING_RIGHT;
    if (max_content_width_ <= viewport_w) return 0.0f;
    return max_content_width_ - viewport_w;
}

float ContentWidget::content_height() const {
    return line_index_.total_content_height();
}

float ContentWidget::content_width() const {
    return max_content_width_;
}

// ============================================================================
// Cursor Control
// ============================================================================

void ContentWidget::move_cursor_to(size_t byte_pos) {
    if (!document_) return;

    // Clamp to document bounds
    size_t max_pos = document_->content()->total_length();
    if (byte_pos > max_pos) byte_pos = max_pos;

    cursor_byte_pos_ = byte_pos;

    // Recalculate line/column
    byte_pos_to_line_column(byte_pos, cursor_line_, cursor_column_);

    // Update preferred column (for vertical navigation)
    cursor_preferred_column_ = cursor_column_;

    // Update cursor target X position
    cursor_target_x_ = get_cursor_x_for_column(cursor_line_, cursor_column_);

    // Set current position immediately (animation will smooth subsequent moves)
    cursor_current_x_ = cursor_target_x_;
    cursor_x_initialized_ = true;

    // Reset blink and ensure cursor is visible
    reset_cursor_blink();
    ensure_cursor_visible();
    set_dirty();
}

void ContentWidget::move_cursor_to_line_column(size_t line, size_t col) {
    if (!document_ || line == 0) return;

    // Clamp line to valid range
    size_t line_count = line_index_.line_count();
    if (line_count == 0) {
        cursor_line_ = 1;
        cursor_column_ = 0;
        cursor_byte_pos_ = 0;
        reset_cursor_blink();
        return;
    }

    if (line > line_count) line = line_count;

    // Clamp column to line length
    size_t line_len = get_line_length_in_columns(line);
    if (col > line_len) col = line_len;

    cursor_line_ = line;
    cursor_column_ = col;
    cursor_byte_pos_ = line_column_to_byte_pos(line, col);

    // Update preferred column (for vertical navigation)
    cursor_preferred_column_ = col;

    // Update cursor target X position
    cursor_target_x_ = get_cursor_x_for_column(cursor_line_, cursor_column_);

    // Set current position immediately (animation will smooth subsequent moves)
    cursor_current_x_ = cursor_target_x_;
    cursor_x_initialized_ = true;

    // Reset blink and ensure cursor is visible
    reset_cursor_blink();
    ensure_cursor_visible();
    set_dirty();
}

void ContentWidget::ensure_cursor_visible() {
    // Vertical scrolling: ensure cursor line is visible
    float cursor_y = (cursor_line_ - 1) * ContentConfig::LINE_HEIGHT;
    float viewport_top = scroll_y_;
    float viewport_bottom = scroll_y_ + rect.height;

    if (cursor_y < viewport_top) {
        // Cursor is above viewport - scroll up
        set_scroll_y(cursor_y);
    } else if (cursor_y + ContentConfig::LINE_HEIGHT > viewport_bottom) {
        // Cursor is below viewport - scroll down
        set_scroll_y(cursor_y + ContentConfig::LINE_HEIGHT - rect.height);
    }

    // Horizontal scrolling: ensure cursor column is visible
    float cursor_x = cursor_target_x_;
    float visible_left = scroll_x_;
    float visible_right = scroll_x_ + rect.width - ContentConfig::PADDING_LEFT - ContentConfig::PADDING_RIGHT;
    constexpr float margin = 20.0f;  // Keep cursor this far from edges

    if (cursor_x < visible_left + margin) {
        set_scroll_x(fmaxf(0.0f, cursor_x - margin));
    } else if (cursor_x > visible_right - margin) {
        set_scroll_x(cursor_x - (rect.width - ContentConfig::PADDING_LEFT - ContentConfig::PADDING_RIGHT) + margin);
    }
}

void ContentWidget::reset_cursor_blink() {
    cursor_blink_timer_ = 0.0f;
    cursor_blink_pause_timer_ = CursorConfig::PAUSE_MS / 1000.0f;
    cursor_opacity_ = 1.0f;
}

