void ContentWidget::tick(float dt) {
    Widget::tick(dt);  // Base class hover animations
    bool needs_redraw = false;

    // === Cursor Position Animation ===
    bool cursor_is_moving = fabsf(cursor_current_x_ - cursor_target_x_) > 0.5f;
    if (cursor_is_moving) {
        float speed = 1000.0f / CursorConfig::MOVE_MS;
        float delta = cursor_target_x_ - cursor_current_x_;
        cursor_current_x_ += delta * fminf(1.0f, speed * dt);
        needs_redraw = true;
    } else {
        cursor_current_x_ = cursor_target_x_;
    }

    // === Cursor Blink Animation ===
    // Only blink when editor is focused, not moving, and pause timer has expired
    if (editor_has_focus(parent)) {
        // Decrement pause timer
        if (cursor_blink_pause_timer_ > 0.0f) {
            cursor_blink_pause_timer_ -= dt;
            // Keep cursor fully visible during pause
            cursor_opacity_ = 1.0f;
            needs_redraw = true;
        } else if (cursor_is_moving) {
            // Cursor is animating - keep fully visible, don't run blink timer
            cursor_opacity_ = 1.0f;
            cursor_blink_timer_ = 0.0f;
            needs_redraw = true;
        } else {
            // Normal blink animation
            cursor_blink_timer_ += dt;
            float period = CursorConfig::BLINK_PERIOD_MS / 1000.0f;
            float fade_time = CursorConfig::FADE_MS / 1000.0f;
            float phase = fmodf(cursor_blink_timer_, period);
            float half_period = period / 2.0f;

            float new_opacity;
            if (phase < fade_time) {
                // Fading out
                new_opacity = 1.0f - Easing::ease_out_quad(phase / fade_time);
            } else if (phase < half_period) {
                // Fully invisible
                new_opacity = 0.0f;
            } else if (phase < half_period + fade_time) {
                // Fading in
                new_opacity = Easing::ease_out_quad((phase - half_period) / fade_time);
            } else {
                // Fully visible
                new_opacity = 1.0f;
            }

            if (fabsf(new_opacity - cursor_opacity_) > 0.01f) {
                cursor_opacity_ = new_opacity;
                needs_redraw = true;
            }
        }
    }

    if (needs_redraw) {
        set_dirty();
    }
}

